[
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 205,
    "severity": "critical",
    "description": "Filter condition is inverted in listFeaturesForUser. The code filters OUT globally enabled features with `!state.globalEnabled`, but the docstring at line 187 explicitly states the method should return 'features that are in the allowlist, globally enabled, and scoped to user'. This is the opposite of the implemented behavior. Compare to listFeaturesForTeam at line 240 which correctly includes features with `result.globalEnabled`. This will cause the method to return no features when globally enabled features exist, breaking the user-facing feature list.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -203,7 +203,7 @@
       featureIds,
     });

-    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => !state.globalEnabled);
+    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
   }

   /**
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 161,
    "severity": "high",
    "description": "Policy is hardcoded to 'permissive' instead of being retrieved from the feature configuration. The OptInFeatureConfig interface defines a required `policy` field (config.ts line 8), and getOptInFeatureConfig is already imported (line 6). The hardcoded policy violates the established pattern of respecting feature configuration and will cause all features to use 'permissive' policy regardless of their configured policy, breaking policy-based access control.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -158,7 +158,8 @@
       userAutoOptIn,
     });

-    const policy: OptInFeaturePolicy = "permissive";
+    const featureConfig = getOptInFeatureConfig(featureId);
+    const policy: OptInFeaturePolicy = featureConfig?.policy ?? "permissive";

     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
       globalEnabled,
"
  },
  {
    "file": "packages/features/feature-opt-in/config.ts",
    "line": 76,
    "severity": "critical",
    "description": "The isFeatureAllowedForScope function doesn't handle optional scope fields correctly. The OptInFeatureConfig.scope field is optional (line 10: `scope?: OptInFeatureScope[]`), and the JSDoc states 'Features without a scope field are allowed for all scopes' (line 71). However, line 76 calls `.includes(scope)` without checking if config.scope is undefined, which will throw a TypeError at runtime. The parallel function getOptInFeaturesForScope (line 65) correctly handles this with `!f.scope || f.scope.includes(scope)`. This inconsistency causes crashes when checking features without a scope field.",
    "fix_patch": "--- a/packages/features/feature-opt-in/config.ts
+++ b/packages/features/feature-opt-in/config.ts
@@ -73,7 +73,7 @@
  */
 export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
   const config = getOptInFeatureConfig(slug);
   if (!config) return false;
-  return config.scope.includes(scope);
+  return !config.scope || config.scope.includes(scope);
 }
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 88,
    "severity": "high",
    "description": "The setUserState mutation is missing input validation for slug against the opt-in allowlist. Both setTeamState (line 117) and setOrganizationState (line 146) validate using `isOptInFeature(input.slug)` and throw a properly formatted TRPCError if invalid. setUserState lacks this validation, creating inconsistent error handling patterns. While the service validates via isFeatureAllowedForScope, it throws ErrorWithCode instead of TRPCError, which may not integrate properly with tRPC's error handling. This violates the established codebase pattern where all mutations validate input in the router layer.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -94,6 +94,13 @@
       })
     )
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
+
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

